        SPECIFICALLY_WE_HAVE_DEVELOPED_A_MEANS_TO_MANIPULATE                                        = 12907,  -- Specifically, we have developed a means to manipulate these boxes so that your preferred items may be extracted with greater ease.
        I_WOULD_EXPLAIN_FURTHER_BUT_THE_INNER_WORKINGS                                              = 12908,  -- I would explain further, but the inner workings of this are beyond a layman like me. Simply convey to me your preferences, and enjoy the newfound convenience on your next expedition.
