        GREETINGS_I_SEE_YOU_HAVE_BEEN_DRAWN_IN                                                      = 14322,  -- Greetings... I see you have been drawn in by the spectacle of my massive magical aura... Do not be embarrassed. You are not the first.
        PERHAPS_I_SHALL_BLESS_YOU_WITH_A_DEMONSTRATION                                              = 14323,  -- Perhaps I shall bless you with a demonstration? I can snatch you up in an eldritch embrace and transport you to a far-off land. How does Jeuno sound?
        BUT_I_MUST_HAVE_A_TRIBUTE_TO_MATCH                                                          = 14324,  -- But I must have a tribute to match my brilliance... Ah yes, % would be perfect!
        THERE_IS_NO_HURRY_THE_STREAM_OF_TIME                                                        = 14325,  -- There is no hurry--the stream of time shall wait for one such as I. When you are prepared, trade me the treasure I ask for and you will find yourself whisked to the center of Jeuno in a twinkling...
        I_SEE_YOU_HAVE_BROUGHT_ME_MY_YOUR                                                           = 14326,  -- I see you have brought me my %. Your tribute has bought you a first-class ticket to the Duchy of Jeuno!
        PREPARE_YOURSELF_FOR_THE_HEIGHT_OF_TELEPORTATION_EXCELLENCE                                 = 14327,  -- Prepare yourself for the height of teleportation excellence!
        THAT_SMELL_YOU_REEK_OF_AMATEUR_SORCERY                                                      = 14328,  -- That smell... You reek of amateur sorcery.
        IT_SEEMS_MY_SUPERIOR_SERVICES_HAVE_BEEN_SPURNED                                             = 14329,  -- It seems my superior services have been spurned for back-alley parlor tricks.
        I_LL_THANK_YOU_TO_TAKE_THAT_OFFENSIVE                                                       = 14330,  -- I'll thank you to take that offensive stink elsewhere.
        I_SEE_YOU_HAVE_DEVELOPED_A_FONDNESS_FOR                                                     = 14331,  -- I see you have developed a fondness for my mystical magnificence.
        AGAIN_YOU_COME_TO_ME_YOU_CAN_NEVER                                                          = 14332,  -- Again, you come to me. You can never forget the enchanted exhiliration that accompanies a top-class teleportation...
        YOU_ARE_A_SLAVE_TO_MY_SUPERLATIVE_SPELLCRAFT                                                = 14333,  -- You are a slave to my superlative spellcraft.
        AND_SINCE_YOU_FIND_ME_IN_HIGH_SPIRITS                                                       = 14334,  -- And since you find me in high spirits this day, I will even consent to transport you to the nation of your allegiance.
        THERE_IS_NO_HURRY_THE_STREAM_OF_TIME_2                                                      = 14335,  -- There is no hurry--the stream of time shall wait for one such as I. When you are prepared, trade me the treasure I ask for and you will find yourself instantly whisked to the center of your destination...
        HAVE_YOU_DECIDED_THE_DESTINATION_FOR_THIS_INTOXICATING                                      = 14336,  -- Have you decided the destination for this intoxicating transit?
