        NOW_LET_ME_MOVE_ON_TO_THE_MERCANTILE                                                        = 14364,  -- Now let me move on to the mercantile metropolis known as the Bastok Markets.
        AND_AFTER_THE_MARKETS_COME_THE_MASSIVE_BASTOK                                               = 14365,  -- And after the markets, come the massive Bastok Mines.
        AND_FINALLY_WHO_COULD_FORGET_THE_MARVELED_BASTOK                                            = 14366,  -- And finally, who could forget the marveled Bastok Metalworks, where masterful minds from across the Republic meet to mull over the mysteries of man-made mechanical marvels.
        LET_ME_START_WITH_THE_WINDURST_WATERS                                                       = 14367,  -- Let me start with the Windurst Waters.
