        OF_COURSE_ANY_ENDEAVOR_HAS_ITS_PRRRICE                                                      = 14396,  -- Of course, any endeavor has its prrrice...
        SLOOOW_DOWN_NOW_WE_WERE_PREPARED_FOR_SUCH                                                   = 14397,  -- Slooow down, now. We were prepared for such an occurrence and are well aware of where our quarry lies. The weapons were outfitted with quartz transmitters which emit precise astral tracking signals.
        SO_YOU_HAVE_ALREADY_PINPOINTED_THE_LOCATION_OF                                              = 14398,  -- So you have already pinpointed the location of the perpetrator?
        THAT_CERTAINLY_SIMPLIFIES_THINGS_IF_WE_WERE_TO                                              = 14399,  -- That certainly simplifies things. If we were to send out all of our mercenaries at once maybe...
