        GASP_2                                                                                      = 14419,  -- <Gasp>!
        YOU_JUST_LEAVE_EVERYTHING_TO_US_WE_LL                                                       = 14420,  -- You just leave everything to us. We'll see to it this mission receives our utmost attention. That's the Salaheem guarrrantee!
        THAT_PLEASES_ME_A_GREAT_DEAL_VERY_WELL                                                      = 14421,  -- That pleases me a great deal. Very well, then. I leave the matter in your capable hands.
        AS_YOU_WISH_SO_SHALL_IT_BE_DONE                                                             = 14422,  -- As you wish, so shall it be done. I will personally see to it that this request is given top priority. We will search rrrelentlessly and none shall rest until the weapons you seek have been recovered and are once again in your possession.
        ID_14423                                                                                    = 14423,  -- ...
        ISN_T_THAT_RIGHT_CAPTAIN                                                                    = 14424,  -- Isn't that right, Captain %?
