        HELLO_THERE_HAVE_YOU_BEEN_ABLE_TO_FIND                                                      = 14426,  -- Hello there, %. Have you been able to find any of the weapons of which we spoke?
        DO_YOU_HAVE_ONE_OF_THE_WEAPONS_RIGHT                                                        = 14427,  -- Do you have one of the weapons? Right here. Not just yet. Ummm... Could I see that list again?
