        I_CANNOT_SAY_THAT_I_M_SURPRISED_THE                                                         = 14429,  -- I cannot say that I'm surprised. The ruins of Nyzul Isle are vast and dangerous. You must be sure to take great care when searching there.
        EVEN_AN_ACCOMPLISHED_CAPTAIN_SUCH_AS_YOURSELF_CANNOT                                        = 14430,  -- Even an accomplished captain such as yourself cannot simply waltz into a place such as that.
        WELL_IN_ANY_EVENT_I_SHALL_PATIENTLY_BE                                                      = 14431,  -- Well, in any event, I shall patiently be awaiting your triumphant return. I only wish the same could be said for President Naja...
