        AND                                                                                         = 14433,  -- %, %, %, %, and %.
        THAT_SEEMS_TO_BE_IT_SO_WHAT_SAY                                                             = 14434,  -- That seems to be it. So, what say you? Have you come across any of these weapons or not?
        DO_ANY_OF_THE_WEAPONS_CATCH_YOUR_FANCY                                                      = 14435,  -- Do any of the weapons catch your fancy? Yes, surely. No, sadly. Give the list another gander.
        THIS_IS_WHAT_ALL_THE_EXCITEMENT_WAS_ABOUT                                                   = 14436,  -- This is what all the excitement was about? Am I missing something here, or does this just look like a rusty old weapon to you, too?
        I_M_SORRY_I_DIDN_T_MEAN_TO                                                                  = 14437,  -- I'm sorry, %. I didn't mean to belittle your efforts. It's just not at all what I had expected.
        PRESIDENT_NAJA_7                                                                            = 14438,  -- President Naja!
        NO_DOUBT_ABOUT_IT_THE_QUARTZ_TRRRANSMITTER_S                                                = 14439,  -- No doubt about it. The quartz trrransmitter's signal is synchronizing perfectly on both ends. This is what we've been looking for.
