        N_NOT_EXACTLY_IT_S_JUST_THAT                                                                = 14450,  -- N-not exactly. It's just that...
        TH_THIS_ISN_T_EXACTLY_THE_INVITATION_TO                                                     = 14451,  -- Th-this isn't exactly the invitation to the palace we had anticipated. It's a... Well, there's some orders written here.
