        WELL_I_LL_BE_SO_THE_BRAZEN_MERCENARY                                                        = 14485,  -- Well I'll be... So the brazen mercenary marches in to save the day and achieves a victory that has eluded the Imperial army for years, eh? I knew I kept you around for a reason!
        I_DO_TEND_TO_BE_RRRIGHT_YOU_KNOW                                                            = 14486,  -- I do tend to be rrright, you know.
        THIS_IMPERIAL_DECREE_CONFIRMS_THAT_THE_THREAT_POSED                                         = 14487,  -- This Imperial decree confirms that the threat posed by the Archaia is indeed a viable one.
        WHAT_S_A_ARCHAIA_I_HOPE_YOU_RE                                                              = 14488,  -- What's a Archaia!? I hope you're joking... They're those metal contrrraptions that are always spotted hovering around the Alzadaal Undersea Ruins.
