        SPEAK_OF_THE_DEVIL_IMPECCABLE_TIMING_ABQUHBAH_CALM                                          = 14520,  -- Speak of the devil! Impeccable timing, Abquhbah. Calm down. Deep breaths. Thaaat's it. Go easy.
        PANT_PANT_PANT                                                                              = 14521,  -- <Pant, pant, pant>...
        IF_YOU_PANT_COULD_JUST_PANT_GIVE_ME                                                         = 14522,  -- If you <pant> could just <pant> give me a moment <pant> to catch m--
        GOOD_NOW_THAT_YOU_VE_COLLECTED_YOURSELF_JUST                                                = 14523,  -- Good! Now that you've collected yourself just go ahead and rrread my invitation aloud.
        THAT_S_KIND_OF_WHAT_I_WANTED_PANT                                                           = 14524,  -- That's kind of what I wanted <pant> to speak with you about, President.
        ABQUHBAAAH                                                                                  = 14525,  -- Abquhbaaah!!!
        OH_DEAR_4                                                                                   = 14526,  -- Oh dear...
        DO_YOU_HAVE_ANY_IDEA_WHAT_WILL_HAPPEN                                                       = 14527,  -- Do you have any idea what will happen if I have to stand here again and listen to you tell me that you don't have an Imperial invitation? Because I certainly don't. All I know is that I won't be rrresponsible for it.
        OH_WELL_THEN_YOU_WILL_BE_VERY_PLEASED                                                       = 14528,  -- Oh, well then you will be very pleased to know that this is indeed an invitation!
        WELL_WHY_DIDN_T_YOU_SAY_SO_SOMETIMES                                                        = 14529,  -- Well why didn't you say so!? Sometimes I think you tear me down just to build me back up again, Abquhbah. You're either very smart or very stupid. In either event, I thank you for trrrying to amplify my happiness.
        YOU_RE_MOST_WELC_OH_OH_DEAR_ACTUALLY                                                        = 14530,  -- You're most welc--oh! Oh dear... Actually, this invitation seems to have been made out to Captain % here.
