        THERE_IS_AFTER_ALL_LITTLE_OF_NASHMEIRA_THAT                                                 = 14562,  -- There is, after all, little of Nashmeira that has not already been made known to us.
        AND_SURELY_YOU_DON_T_INTEND_TO_CHOOSE                                                       = 14563,  -- And surely you don't intend to choose now of all times to mire us all in the observation of formalities?
        SURELY_HIS_HER_PRESENCE_HERE_ALONE_IS_EVIDENCE                                              = 14564,  -- Surely his/her] presence here alone is evidence of his/her] having proven himself/herself] as a hero/heroine] of the Empire.
        NOT_EVEN_THE_EMPRESS_S_GREAT_UNCLE_ZARAFEEHL                                                = 14565,  -- Not even the Empress's great uncle Zarafeehl in the eastern realm of Sahjattra could voice his opposition under such circumstances.
