        YES_YES_YOU_HAVE_THE_RIGHT_OF_IT                                                            = 14619,  -- Yes... Yes, you have the right of it, I should think. Forgive me my apprehensions.
        AGAIN_YOU_HAVE_OUR_DEEPEST_THANKS_YOU_HAVE                                                  = 14620,  -- %, again you have our deepest thanks. You have delivered us safely from yet another potential disaster.
        I_THINK_NONE_HERE_WOULD_OBJECT_NOR_CALL                                                     = 14621,  -- I think none here would object, nor call it an overstatement, to say that it is you, %, who is the true treasure of Aht Urhgan!
        A_PARAGON_OF_EXCELLENCE_AND_BEACON_TO_THE                                                   = 14622,  -- A paragon of excellence, and beacon to the Empire!
        MONEY_SWEET_MONEY_MAKES_THE_WORLD_GO_ROUND                                                  = 14623,  -- Money, sweet money, makes the world go 'round!t
