        NEVER_AGAIN_SHALL_I_HAVE_A_WORRY_OR                                                         = 14625,  -- Never again shall I have a worry or care!t
        NEVER_AGAIN_SHALL_OUR_COFFERS_RUN_BARE_T                                                    = 14626,  -- Never again shall our coffers run bare!t
        SALAHEEM_S                                                                                  = 14627,  -- Salaheem's...!
        SENTINELS_2                                                                                 = 14628,  -- Sentinels!
        SENTINELS_3                                                                                 = 14629,  -- Sentinels!
        AND_NOW_YOU_SEE_THE_FUN_JUST_BEGINS                                                         = 14630,  -- And now, you see, the fun just begins!
        FOR_GOLD_IT_IS_KNOWN_YIELDS_GOLD_YET                                                        = 14631,  -- For gold, it is known, yields gold yet again!
        NO_MATTER_THE_RIVERS_OF_BLOOD_WE_MUST                                                       = 14632,  -- No matter the rivers of blood we must spill!
