        PRESIDENT_NAJA_HASN_T_STOPPED_CELEBRATING_SINCE_SHE                                         = 14637,  -- (President Naja hasn't stopped celebrating since she woke this morning. She's absolutely drunk on coinage! I'm having a hard time keeping up. I never had much of a gift for rhyme...)
        THANK_YOU_DEAR_EMPRESS_OH_THANK_YOU_INDEED                                                  = 14638,  -- Thank you dear Empress, oh thank you indeed!t
        JUST_BETWEEN_YOU_AND_ME_THE_ROYAL_HOUSE                                                     = 14639,  -- (Just between you and me, the royal house paid a sum for this most recent endeavor of yours that put even the first-tier Mog Bonanza winners to shame.)
        OF_COURSE_YOU_CAN_EXPECT_TO_RECEIVE_A                                                       = 14640,  -- (Of course, you can expect to receive a handsome bonus for your--)
        AH_THAT_REMINDS_ME_CAPTAIN_YOU_VE_OUTDONE                                                   = 14641,  -- Ah, that reminds me! Captain %! You've outdone yourself this time, haven't you?
        I_HAVE_YOU_TO_THANK_FOR_THIS_LITTLE                                                         = 14642,  -- I have you to thank for this little financial windfall of ours. It's only fitting that you be presented with a reward befitting your distinguished service!
        SEE_WHAT_DID_I_TELL_YOU_EVEN_THE                                                            = 14643,  -- (See? What did I tell you? Even the President herself can't be stingy with all this money around!)
