        MY_ATTENDANT_WOULD_BE_HONORED_TO_COMPLY                                                     = 14765,  -- My attendant would be honored to comply!
        AFTER_ALL_I_CAN_T_NEGLECT_MY_COMPOSITIONAL                                                  = 14766,  -- (After all, I can't neglect my compositional pursuits for too long. If my latest masterpiece were delayed, my fans all over the Empire--nay, the world--will be rioting in the streets! Surely you understand.)
