        F_OH_OM_L_3_AD_JH_HIHIC                                                                     = 14768,  -- %*F$%Oh(%OM %<L+3\*AD=Jh #hIHic>ccI
        OH_MY_ATTENDANT_EVER_THE_LEISURELY_FELLOW_LASS                                              = 14769,  -- Oh, my attendant! Ever the leisurely fellow/lass], aren't you? Listen, the streets are positively abuzz! Rumor has it that the traitor is a high-ranking Imperial general!
        I_WOULD_HAVE_BEEN_ABLE_TO_RUSH_IN                                                           = 14770,  -- I would have been able to rush in for the exclusive scoop if I wasn't stuck here waiting for you! How are you going to make it up to me this time? Hmmmmmm?
        MASTER_FARI_WARI_MY_APOLOGIES_IF_I_VE                                                       = 14771,  -- Master Fari-Wari. %. My apologies if I've kept you waiting.
        YOU_MOST_CERTAINLY_HAVE_I_TELL_YOU_THE                                                      = 14772,  -- You most certainly have. I tell you, the moss that was growing on me is now growing its own moss! So Shayadar, good man, are the stories true?
        THEY_ARE_NO_SOONER_HAD_GENERAL_GADALAR_PRESENTED                                            = 14773,  -- They are. No sooner had General Gadalar presented himself than he proceeded to confront the traitorous Malzaab in front of the whole committee. Which was all well and good, of course, but...
