        GJ_K_3_M_LPB_O5D_FQE_H                                                                      = 14775,  -- },%gj=K_3\M LpB/o5D FqE`H"ZI m9=g5"ccB
        AND_THE_HALL_WAS_LEFT_IN_SHAMBLES                                                           = 14776,  -- ...And the hall was left in shambles?
        INDEED_TIS_NOT_LIKELY_TO_GO_UNPUNISHED_STILL                                                = 14777,  -- Indeed. 'Tis not likely to go unpunished. Still, needless to say, he's been cleared of all allegations of treason.
        NOW_THAT_S_A_RELIEF                                                                         = 14778,  -- Now that's a relief!
        VERILY                                                                                      = 14779,  -- Verily.
        OHO_WHICH_REMINDS_ME_IT_MIGHT_NOT_BE                                                        = 14780,  -- Oho, which reminds me! It might not be much, but here's a humble reward for your efforts.
        A_PRESENT_FOR_FARI_WARI_THE_COURAGEOUS_SHAYADAR                                             = 14781,  -- A present for Fari-Wari the Courageous? Shayadar, my good man, you're far too kind! After all, I did little but risk life, limb, and my most fashionable attire in a selfless attempt to defend the Flameserpent General's honor--
        AH_MY_PARDONS_MASTER_FARI_WARI_I_M                                                          = 14782,  -- Ah... My pardons, Master Fari-Wari. I'm under strict orders from the gift's bestower to present it directly to %.
        WH_WHAT_THE_INDIGNITY_WHO_COULD_POSSIBLY_BE                                                 = 14783,  -- Wh-what!? The indignity! Who could possibly be so callous as to say such a thing?
        HAH_HAH_I_M_AFRAID_I_COULDN_T                                                               = 14784,  -- Hah hah, I'm afraid I couldn't say...
        I_MUST_SAY_THOUGH_IT_S_STILL_A                                                              = 14785,  -- I must say, though, it's still a mystery to me. What possessed General Gadalar to go around at night with that % in hand?
        IT_S_INTERESTING_THAT_THE_IS_USED_IN                                                        = 14786,  -- It's interesting, that. The % is used in our army to pay tribute to the spirits of our fallen comrades. A symbol of our bonds of loyalty, as it were.
        TIS_ALSO_KNOWN_AS_THE_FLOWER_OF_MANY                                                        = 14787,  -- 'Tis also known as the "Flower of Many Faces." Its petals shift color, from one brilliant hue to the next.
        I_SUSPECT_GENERAL_GADALAR_WAS_PAYING_TRIBUTE_IN                                             = 14788,  -- I suspect General Gadalar was paying tribute, in his own way... To his fallen comrades, and to that Elvaan lass who now stands with our foes.
        AND_SO_HE_CAST_THOSE_MANY_COLORED_PETALS                                                    = 14789,  -- And so he cast those many-colored petals into the ocean. That no matter how many leagues separate them as their worlds drift further and further apart... That the bonds they once shared should never break.
        INCREDIBLE                                                                                  = 14790,  -- Incredible...!
        REALLY_THOUGH_TIS_ONLY_IDLE_CONJECTURE                                                      = 14791,  -- Really though, 'tis only idle conjecture.
        WHY_FRIEND_SHAYADAR_OF_COURSE_OF_COURSE_IT                                                  = 14792,  -- Why, friend Shayadar...of course! Of course! It couldn't be more obvious!
        JP_AD_LG_M_K_3_IO_I                                                                         = 14793,  -- ;jp=.AD LG@%M K_3\Io"I%=L)`5jJHccB
        THAT_THE_PETALS_WOULD_FLOAT_OUT_INTO_THE                                                    = 14794,  -- That the petals would float out into the open sea, ride the waves across leagues of ocean, and someday find their way to the East-- ...To the delicate hands of his eternal love, the fair Shayeeha!
        HOW_THOROUGHLY_HOW_HEART_MELTINGLY_ROMANTIC_A_LOVE                                          = 14795,  -- How thoroughly, how heart-meltingly romantic! A love story for the ages!
        A_A_WHAT_NO_NO_YOU_SEE_YOU                                                                  = 14796,  -- A...a what? No, no, you see, you've got it all wrong--
        SHAYADAR_MY_GOOD_MAN_I_THINK_NOT_I                                                          = 14797,  -- Shayadar, my good man, I think not! I couldn't be more right!
        I_KNEW_IT_UNDER_THAT_ROUGH_AND_RUGGED                                                       = 14798,  -- I knew it! Under that rough and rugged exterior, the Flameserpent General's heart burns with the ardent flames of passion! A furious rapture that shall not be contained!
        WHAT_S_THIS_TRA_LA_T_TRU_LU                                                                 = 14799,  -- What's this...!? Tra-la!t Tru-lu-lu!t Tri-li-li-li-li!t
        MY_HEART_IS_AFLUTTER_I_CAN_BARELY_BREATHE                                                   = 14800,  -- My heart is aflutter... I can barely breathe... There's no mistaking this feeling... Yes, inspiration! Inspiration has struck!
