        IT_S_TO_THE_POINT_THAT_A_POOR                                                               = 14823,  -- It's to the point that a poor bard can't even concentrate on writing his melodies! I tell you, I've half a mind to tell that ruffian to--<gulp>!
        AH_FANCY_MEETING_YOU_IN_A_PLACE_LIKE                                                        = 14824,  -- Ah, %. Fancy meeting you in a place like this.
        WHICH_REMINDS_ME_I_HAVE_A_MESSAGE_FOR                                                       = 14825,  -- Which reminds me. I have a message for you here, jointly issued by the Serpent Generals five.
