        DAMN_IT_ALL                                                                                 = 14831,  -- Damn it all!
        WHO_WROTE_THIS_OVERBLOWN_TEDIOUS_MIND_NUMBING_DRIVEL                                        = 14832,  -- Who wrote this overblown, tedious, mind-numbing drivel!?
        THE_POINT_IS_YOU_VE_MADE_QUITE_A                                                            = 14833,  -- The point is, you've made quite a name for yourself around these parts, and the Serpent Generals are itching for a chance to cross blades with you.
        MYSELF_INCLUDED_OF_COURSE_HEH_HEH_HEH                                                       = 14834,  -- Myself included, of course. Heh heh heh...
        AND_DON_T_EXPECT_ANY_QUARTER_JUST_BECAUSE                                                   = 14835,  -- And don't expect any quarter just because you did me a small favor. You might stand a chance against the others, but you'd best say your graces before facing my flames.
        DON_T_GO_FLEEING_THE_EMPIRE_NOW                                                             = 14836,  -- Don't go fleeing the Empire, now!
        WHAT_S_THAT                                                                                 = 14837,  -- What's that? %?
        COULD_THIS_MEAN_WHAT_I_THINK_IT_MEANS                                                       = 14838,  -- Could this mean what I think it means? A personal challenge from the Serpent Generals!?
        THE_LETTER_SAYS_YOU_RE_TO_MEET_THEM                                                         = 14839,  -- The letter says you're to meet them at the Stellar Fulcrum in some place called Delkfutt's Tower. Go give that Gadalar a good thrashing for me!
        AH_BUT_HOW_FAR_YOU_VE_COME_TO                                                               = 14840,  -- Ah, but how far you've come, %! To think that the feeble sop who stumbled in here begging me for a job is now the personal sparring partner of the Serpent Generals!
        SNIFF_IT_ALMOST_BRINGS_A_TEAR_TO_MY                                                         = 14841,  -- <Sniff>... It almost brings a tear to my eye... Though it's no surprise, really. You did, after all, have a superlative mentor.
        WELL_JUST_TRY_NOT_TO_GET_YOURSELF_KILLED                                                    = 14842,  -- Well, just try not to get yourself killed now, okay? After all, I just might be needing your help with my next masterpiece...!
        WHAT_D_YA_MEAN_YOU_CAN_T_FIND                                                               = 14843,  -- What d'ya mean you can't find him/her]!?
        IF_YA_CAN_T_KEEP_MY_MERCENARIES_IN                                                          = 14844,  -- If ya can't keep my mercenaries in order, I'll just hafta to find myself a new assistant who can!
        AH_Y_YES_PRESIDENT_NAJA_MA_AM_WITH                                                          = 14845,  -- Ah, y-yes, President Naja, ma'am. With Falzum on the search, I'm sure that any m-minute now--
        ANY_MINUTE_NOW_AIN_T_GOOD_ENOUGH_THE                                                        = 14846,  -- Any minute now ain't good enough! The rrreputation of Salaheem's Sentinels is at stake!
        Y_YES_MA_AM_GULP_P_PLEASE_DON                                                               = 14847,  -- Y-yes, ma'am! (<Gulp>... P-please don't fire me!)
        IN_DESPERRRATE_TIMES_YA_GOTTA_THINK_OUTSIDE_THE                                             = 14848,  -- In desperrrate times, ya gotta think outside the box. A bounty of ten Imperial gold pieces on %'s hide should do the trrrick, I'd wager...
        BUT_P_PRESIDENT_NAJA_SHE_CAN_T_BE                                                           = 14849,  -- But, P-President Naja...! (She can't be serious...or can she?)
        THANK_HEAVENS_IT_S_YOU_YOU_ALWAYS_HAVE                                                      = 14850,  -- %! Thank heavens it's you! (You always have the most remarkable timing!)
        WHERE_IN_THE_EMPIRE_HAVE_YOU_BEEN_I                                                         = 14851,  -- %! Where in the Empire have you been!? I don't recall grrrantin' yer slackin' behind any holiday leave!
        WHY_I_VE_HAD_IT_UP_TO_HERE                                                                  = 14852,  -- Why, I've had it up to here with your insubordination! You insolent, ungrrrateful...
        BUMBLING_BLUNDERING                                                                         = 14853,  -- ...bumbling, blundering...
        CROSS_EYED_PUDDING_BRAINED_TROLL_FACED_LOUT                                                 = 14854,  -- ...cross-eyed, pudding-brained, troll-faced lout!
        OUCH_WHY_DOES_SHE_ALWAYS_HAVE_TO_MAKE                                                       = 14855,  -- (Ouch. Why does she always have to make it personal?)
        WHAT_I_M_SAYIN_IS_YA_VE_BEEN                                                                = 14856,  -- What I'm sayin' is, ya've been summoned to the Imperrrial Palace! The Empress only knows what they want with yer sorry self, but an order's an order.
        NOW_ARE_YA_JUST_GONNA_STAND_AROUND_WITH                                                     = 14857,  -- Now are ya just gonna stand around with that dopey exprrression on your face?
        CAUSE_MY_LITTLE_FRIEND_HERE_D_BE_HAPPY                                                      = 14858,  -- 'Cause my little friend here'd be happy to give ya some extrrra encouragement. Ya catchin' my drift, %?
        YOU_HONOR_US_WITH_YOUR_PRESENCE                                                             = 14859,  -- %. You honor us with your presence.
        FORGIVE_US_IF_WE_DISPENSE_WITH_THE_PLEASANTRIES                                             = 14860,  -- Forgive us if we dispense with the pleasantries. We have summoned you today to discuss a matter of utmost importance.
        MASTER_GHATSAD_IF_YOU_WOULD                                                                 = 14861,  -- Master Ghatsad, if you would.
        I_TRUST_YOU_REMEMBER_THE_IRON_COLOSSUS                                                      = 14862,  -- %. I trust you remember the iron colossus?
        DO_YOU_REMEMBER_THE_IRON_COLOSSUS_DO_I                                                      = 14863,  -- Do you remember the iron colossus? Do I ever! The iron cowhatsits?
        YES_THE_EVENTS_OF_THAT_DAY_ARE_BURNED                                                       = 14864,  -- Yes, the events of that day are burned into my memory as well. In that case, let us delve straight into the heart of the matter.
        HM_I_SUPPOSE_IT_IS_A_MEMORY_YOU                                                             = 14865,  -- Hm. I suppose it is a memory you care not to recall. You and Her Majesty risked life and limb to silence the rampaging machine and bring peace to our Empire once more.
        IT_WAS_NOT_BY_OUR_STRENGTH_ALONE_GHATSAD                                                    = 14866,  -- It was not by our strength alone, Ghatsad. Were it not for the sacrifices of Prince Luzaf and...my brother...we would never have succeeded that day.
        QUITE_SO_FORGIVE_ME_YOUR_HIGHNESS                                                           = 14867,  -- Quite so. Forgive me, Your Highness.
        AFTER_THE_DUST_SETTLED_WE_SEALED_THE_CHAMBER                                                = 14868,  -- After the dust settled, we sealed the chamber, my research team monitoring the remains closely to ensure that such a calamity would never again befall the Empire.
        ALL_WAS_IN_ORDER_UNTIL_RECENTLY                                                             = 14869,  -- All was in order...until recently.
        A_SPATIAL_DISTORTION_AN_ASTRAL_GATE_AS_THE                                                  = 14870,  -- A spatial distortion--an Astral Gate, as the Windurstian ambassador put it... The fluctuations are so subtle as to be almost undetectable, but something is clearly amiss.
        AN_UNIDENTIFIED_ENERGY_SOURCE_PUSHING_AGAINST_THE_GATE                                      = 14871,  -- An unidentified energy source, pushing against the gate from beyond...as if some extradimensional being is straining to cross over into our world.
        I_M_SURE_YOU_CAN_FORM_A_HYPOTHESIS                                                          = 14872,  -- I'm sure you can form a hypothesis as well as I, %. Yes, I speak of the god who descended into the colossus that day...
        ALEXANDER                                                                                   = 14873,  -- ...Alexander.
        WE_HAVE_YET_TO_OBJECTIVELY_VERIFY_THIS_BUT                                                  = 14874,  -- We have yet to objectively verify this, but there can be no other explanation. Even now, the colossus remains a divine vessel...and thus, a significant danger.
        PERHAPS_YOU_ARE_AWARE_BUT_THIS_IS_NOT                                                       = 14875,  -- Perhaps you are aware, but this is not the only spatial distortion within Imperial territory. A similar phenomenon exists at Hazhalm, where my team and I work tirelessly to develop a means to seal it permanently.
        AS_A_SCIENTIST_IT_PAINS_ME_TO_ADMIT                                                         = 14876,  -- As a scientist, it pains me to admit this, but our technology has proven too primitive, our knowledge too limited for the task.
        STILL_ONE_THING_IS_CLEAR_WE_MUST_ADDRESS                                                    = 14877,  -- Still, one thing is clear: we must address the situation, and without delay.
        GHATSAD_ASSURES_ME_THAT_LEAVING_THE_DISTORTION_UNTOUCHED                                    = 14878,  -- Ghatsad assures me that leaving the distortion untouched would have only one result. We must not--we will not--inflict the suffering of that day upon our people anew.
        AND_SO_IT_IS_THAT_WE_HAVE_MADE                                                              = 14879,  -- And so it is that we have made our decision. We shall repair the colossus and bring it to life ourselves!
        AH_BUT_DO_NOT_BE_STARTLED_ALLOW_ME                                                          = 14880,  -- Ah, but do not be startled. Allow me to explain.
        OUR_OBSERVATIONS_CONFIRM_THAT_THE_DISTORTION_IS_STILL                                       = 14881,  -- Our observations confirm that the distortion is still in the early stages of development. Even if the extradimensional force were to interfere at this stage, its powers would be considerably limited.
        IF_WE_ACT_QUICKLY_WE_CAN_COUNTERACT_THE                                                     = 14882,  -- If we act quickly, we can counteract the disturbance from this side. We take a minor risk now to avert certain disaster later.
        NEEDLESS_TO_SAY_NO_PLAN_IS_FOOLPROOF_THIS                                                   = 14883,  -- Needless to say, no plan is foolproof. This is where you come in, %.
        WE_WOULD_ENTRUST_YOU_WITH_THE_DEACTIVATION_OF                                               = 14884,  -- We would entrust you with the deactivation of the colossus. From your efforts last time, I'd say you're more than up to the task.
        FURTHERMORE_AS_A_SHOW_OF_FAITH_TO_THE                                                       = 14885,  -- Furthermore, as a show of faith to the nations of the Middle Lands, we intend to conduct the entire operation under their strict supervision.
        PAST_EVENTS_BEING_AS_THEY_ARE_IT_IS                                                         = 14886,  -- Past events being as they are, it is our responsibility to assure our friends that we mean them no harm. %. I would ask you to be my envoy.
        HEAR_NASHMEIRA_S_PLEA_MY_HONOR_TO_SERVE                                                     = 14887,  -- Hear Nashmeira's plea? My honor to serve. I fear I cannot...
        THANK_YOU_ONCE_AGAIN_YOU_PROVE_A_TRUE                                                       = 14888,  -- Thank you, %. Once again, you prove a true friend to the Empire.
        WHY_YOU_YOU_D_SO_CALLOUSLY_REFUSE_A                                                         = 14889,  -- Why, you...! You'd so callously refuse a heartfelt plea from Her Imperial Highness?
        AND_HERE_I_THOUGHT_YOU_WERE_A_FRIEND                                                        = 14890,  -- And here I thought you were a friend to the Empire...to us!
        WE_UNDERSTAND_THAT_THE_TASK_IS_AN_ONEROUS                                                   = 14891,  -- We understand that the task is an onerous one. And yet, we have nowhere else to turn.
        GHATSAD_PLEASE                                                                              = 14892,  -- ...Ghatsad, please.
        I_VE_DRAFTED_A_MISSIVE_TO_THE_FOUR                                                          = 14893,  -- I've drafted a missive to the four nations, explaining in detail the predicament we face, and our proposed solution. It should be sufficient to convince our allies of the urgency of our cause.
        YOU_MUST_DELIVER_IT_TO_JEUNO_WITH_ALL                                                       = 14894,  -- You must deliver it to Jeuno with all speed. We are in your debt, %.
        YOU_VE_DONE_IT_THANK_YOU_I_KNEW                                                             = 14895,  -- You've done it! Thank you, %. I knew we could not go wrong with you as our envoy.
        SMASHING_WORK_NEVER_DOUBTED_YOU_FOR_A_MOMENT                                                = 14896,  -- Smashing work! Never doubted you for a moment!
        GHATSAD_IF_YOU_WOULD_BRIEF_ON_WHERE_WE                                                      = 14897,  -- Ghatsad, if you would brief % on where we stand.
        OF_COURSE_YOUR_MAJESTY                                                                      = 14898,  -- Of course, Your Majesty.
        THANKS_TO_YOUR_QUICK_ACTION_THE_DISTORTION_REMAINS                                          = 14899,  -- Thanks to your quick action, the distortion remains fairly stable. We should not encounter significant interference.
        THERE_IS_HOWEVER_ONE_LINGERING_CONCERN_FINDING_A                                            = 14900,  -- There is, however, one lingering concern...finding a suitable power source. Using one of our prototype candescences, I fear, would be far too risky.
        FORTUNATELY_THERE_IS_ANOTHER_OPTION                                                         = 14901,  -- Fortunately, there is another option...%.
        WHATEVER_IS_THAT                                                                            = 14902,  -- %? Whatever is that?
        IN_LAYMAN_S_TERMS_IT_IS_A_RECEPTACLE                                                        = 14903,  -- In layman's terms, it is a receptacle of sorts capable of storing--and releasing--the power of lightning.
        IT_IS_A_DEVICE_OF_YESTERYEAR_AND_THEREIN                                                    = 14904,  -- It is a device of yesteryear...and therein lies the rub. Not a single engineer in the Empire today possesses the knowledge to build one.
        AND_SO_IT_IS_THAT_WE_CALL_UPON                                                              = 14905,  -- And so it is that we call upon your services again, %.
        THERE_IS_ONE_WHO_COMMANDS_THE_KNOWLEDGE_THAT                                                = 14906,  -- There is one who commands the knowledge that has been lost to us...the mad Moblin scientist Megomak.
        PERHAPS_YOU_VE_HEARD_OF_HIM                                                                 = 14907,  -- Perhaps you've heard of him?
        NEEDLESS_TO_SAY_IT_WOULD_BE_OUT_OF                                                          = 14908,  -- Needless to say, it would be out of the question for an official representative of the Empire to consort with a beastman. And so we turn to you, our most loyal and capable mercenary.
        MEGOMAK_IS_AS_ARROGANT_AS_THEY_COME_AND                                                     = 14909,  -- Megomak is as arrogant as they come, and it is unlikely he'll cooperate with us readily. That's why I've taken the liberty of preparing a bit of...extra incentive.
        I_SHALL_PROCEED_TO_NYZUL_ISLE_TO_READY                                                      = 14910,  -- I shall proceed to Nyzul Isle to ready the colossus for activation. Meet me there after you've procured the %.
        DO_BE_CAREFUL                                                                               = 14911,  -- Do be careful, %.
        WE_KNOW_YOU_WON_T_LET_US_DOWN                                                               = 14912,  -- We know you won't let us down!
        HOW_CAN_WE_EVER_REPAY_YOU                                                                   = 14913,  -- %. How can we ever repay you?
        MY_PEOPLE_NEED_LIVE_IN_FEAR_OF_THE                                                          = 14914,  -- My people need live in fear of the colossus no longer. Your efforts have brought peace to the Empire once more.
        AND_A_DAY_FOR_WHICH_I_NEVER_DARED                                                           = 14915,  -- And a day for which I never dared to hope has come. I have been reunited with my dear lost brother.
        THANK_YOU_THANK_YOU_YOU_ARE_THE_TRUE                                                        = 14916,  -- Thank you... Thank you, %. You are the true guardian of the Empire...
        I_OWE_YOU_MY_GRATITUDE_AS_WELL_THIS                                                         = 14917,  -- I owe you my gratitude as well, %. This makes the second time you've helped this scientist avert a catastrophe of colossal proportions.
        AS_FOR_LORD_RAZFAHD_HE_RESTS_NOW_IN                                                         = 14918,  -- As for Lord Razfahd, he rests now in his chambers, weakened yet stable. He will survive.
        IT_S_ALMOST_INCONCEIVABLE_STRANDED_AS_HE_WAS                                                = 14919,  -- It's almost inconceivable, stranded as he was for so long beyond the distortion--in the astral plane, your people call it?
        THE_BLEAK_WIND_THAT_GUSTS_THERE_IS_AS                                                       = 14920,  -- The bleak wind that gusts there is as poison to us. Any period of extended exposure is scientifically proven to be fatal.
        AND_YET_LORD_RAZFAHD_HAS_RETURNED_ALIVE_CAN                                                 = 14921,  -- And yet, Lord Razfahd has returned alive. Can you hypothesize as to why, %?
        THE_AZURE_BLOOD_THAT_FLOWS_WITHIN_HIS_VEINS                                                 = 14922,  -- The azure blood that flows within his veins. The blood of beasts that robbed him of a throne, the blood he so despises... In the end, this blood was his salvation. It would seem fate has a sense of irony...
        BUT_I_HAVE_RAMBLED_ON_LONG_ENOUGH                                                           = 14923,  -- ...But I have rambled on long enough.
        IN_ANY_EVENT_THE_FEE_FOR_YOUR_SERVICES                                                      = 14924,  -- In any event, the fee for your services has been paid in full. You will receive your share from President Naja upon your return, no doubt.
        IT_WOULD_NOT_BE_AN_OVERSTATEMENT_TO_SAY                                                     = 14925,  -- It would not be an overstatement to say that the Empire considers your efforts invaluable. You can expect a healthy reward.
        THIS_IS_WHERE_I_WOULD_LIKE_TO_SHAKE                                                         = 14926,  -- This is where I would like to shake your hand, and send you on your way without a care. ...Sadly, things are not so simple.
        THE_IMMEDIATE_CRISIS_HAS_BEEN_AVERTED_AND_YET                                               = 14927,  -- The immediate crisis has been averted. And yet, it remains beyond our abilities to seal the distortion permanently.
        AND_SO_WE_MUST_REMAIN_EVER_VIGILANT_AGAINST                                                 = 14928,  -- And so we must remain ever vigilant against intruders from beyond. I fear it is not a matter of if, but when.
        EVEN_AS_WE_SPEAK_A_SECOND_DISTORTION_ALSO                                                   = 14929,  -- Even as we speak, a second distortion also displays disturbing activity deep within the Hazhalm Testing Grounds. You can hypothesize as well as I.
        HE_WHO_WILL_NOT_REST_UNTIL_HE_SEES                                                          = 14930,  -- He who will not rest until he sees bloody Ragnarok come to our world... The Dark Rider, Odin.
        MY_TEAM_AND_I_WILL_REDOUBLE_OUR_EFFORTS                                                     = 14931,  -- My team and I will redouble our efforts to develop a permanent seal for the distortion. Until that day comes, we may have occasion to call upon your strength once more.
        YOU_ARE_A_VITAL_ALLY_TO_THE_EMPIRE                                                          = 14932,  -- You are a vital ally to the Empire, %. Promise us that you will remain as such.
        AND_WITH_THAT_YOUR_MAJESTY_I_MUST_TAKE                                                      = 14933,  -- And with that, Your Majesty, I must take my leave. My apprentices will grow suspicious if I neglect my duties at the workshop any longer.
        UNTIL_WE_MEET_AGAIN                                                                         = 14934,  -- Until we meet again.
        TRY_AS_I_MIGHT_I_CANNOT_FIND_THE                                                            = 14935,  -- Try as I might, I cannot find the words to express my gratitude to you, %.
        A_MERCENARY_OF_PEERLESS_BRAVERY_AND_SKILL_STRONG                                            = 14936,  -- A mercenary of peerless bravery and skill, strong of mind and pure of heart. One who understands our every burden and challenge, and comes running to our aid at a moment's notice.
        WHY_WITH_YOU_AT_OUR_SIDE_THERE_IS                                                           = 14937,  -- Why, with you at our side, there is no tempest we cannot weather...no mountain we cannot climb! If only you could stay here at our palace and protect us forever and ev--
        SETTLE_DOWN_NASHMEIRA_CAN_T_YOU_SEE_THAT                                                    = 14938,  -- Settle down, Nashmeira. Can't you see that you're making your guest uncomfortable?
        BROTHER_WHAT_ARE_YOU_DOING_UP_AND_ABOUT                                                     = 14939,  -- Brother! What are you doing up and about!? The healers say that you mustn't exert yourself!
        WORRY_NOT_THE_BETTER_PART_OF_MY_STRENGTH                                                    = 14940,  -- Worry not. The better part of my strength has returned. More importantly, there is something I must say.
        I_HAVE_NO_INTENTION_OF_ASKING_FOR_YOUR                                                      = 14941,  -- %. I have no intention of asking for your forgiveness.
        FOR_I_AM_NOT_DESERVING_OF_IT_NOR                                                            = 14942,  -- ...For I am not deserving of it. Nor will I attempt to justify the crazed acts of a heart consumed with thirst for power. Bitter regret at the horrors I inflicted upon our peoples will be my constant companion for the rest of my days.
        BUT_YOU_EVEN_HAVING_BORNE_WITNESS_TO_MY                                                     = 14943,  -- But you... Even having borne witness to my grievous crimes...still, you saved me.
        THANK_YOU_3                                                                                 = 14944,  -- Thank you, %.
        BROTHER_PLEASE_YOU_MUSTN_T_SPEAK_OF_YOURSELF                                                = 14945,  -- Brother, please! You mustn't speak of yourself so...!
        I_KNOW_THAT_YOU_DID_ONLY_WHAT_YOU                                                           = 14946,  -- I know that you did only what you thought best for the Empire! That your love for your nation is second to none!
        LISTEN_TO_ME_NASHMEIRA                                                                      = 14947,  -- Listen to me, Nashmeira.
        UNDER_YOUR_REIGN_AHT_URHGAN_SHALL_KNOW_PEACE                                                = 14948,  -- Under your reign, Aht Urhgan shall know peace and prosperity as never before. And every step of the journey, I shall walk beside you. Not as Grand Vizier, but as Razfahd--your brother. This I vow.
        BROTHER                                                                                     = 14949,  -- Brother...
        OUR_EMPIRE_HAS_STILL_A_LONG_ROAD_AHEAD                                                      = 14950,  -- %. Our Empire has still a long road ahead. Promise me that you will watch over us. Over her...
        IT_S_RRRAAAINING_GOLD_PRAISE_THE_EMPRESS_T                                                  = 14951,  -- It's rrraaaining gold--praise the Empress!t
        IT_S_RRRAINING_GOLD_T                                                                       = 14952,  -- It's rrraining gold...t
        CAN_YOU_BELIEVE_IT_SHE_S_BEEN_LIKE                                                          = 14953,  -- Can you believe it, %? She's been like this all day. (Funny how she only notices us when things go wrong.)
        AN_UNEARTHLY_VOICE_SPEAKS_FROM_THE_AIR_AROUND                                               = 14954,  -- An unearthly voice speaks from the air around you...
        MORTAL_YOU_HAVE_BEEN_JUDGED_WORTHY_SPEAK_AND                                                = 14955,  -- Mortal...you have been judged...worthy... Speak...and that...which you desire...shall be yours...
        SPEAK_YOUR_DESIRE_COLD_HARD_GIL_A_PACT                                                      = 14956,  -- Speak your desire... %. %. %. Cold, hard gil. A pact with Alexander.
        THAT_IS_YOUR_TRUE_DESIRE                                                                    = 14957,  -- That...is your true...desire...?
        ACCEPT_YES_ON_SECOND_THOUGHT                                                                = 14958,  -- Accept %? Yes. On second thought...
        ACCEPT_A_MONETARY_REWARD_YES_ON_SECOND_THOUGHT                                              = 14959,  -- Accept a monetary reward? Yes. On second thought...
        ACCEPT_THIS_REWARD_YES_ON_SECOND_THOUGHT                                                    = 14960,  -- Accept this reward? Yes. On second thought...
        YOU_HAVE_GAINED_THE_ABILITY_TO_SUMMON_ALEXANDER                                             = 14961,  -- You have gained the ability to summon Alexander!
        IS_EVERYTHING_ALL_RIGHT                                                                     = 14962,  -- Is everything all right, %?
        YOU_SEEM_SOMEHOW_DIFFERENT_FROM_A_MOMENT_AGO                                                = 14963,  -- You seem somehow...different from a moment ago.
        WELL_WELL_IF_IT_ISN_T_MAKING_HIS                                                            = 14964,  -- Well, well, if it isn't [/Private Second Class/Private First Class/Superior Private/Lance Corporal/Corporal/Sergeant/Sergeant Major/Chief Sergeant/Second Lieutenant/First Lieutenant/Captain] % making his/her] triumphant return.
        ONCE_AGAIN_YA_VE_MANAGED_TO_EARRRN_US                                                       = 14965,  -- Once again, ya've managed to earrrn us quite a windfall.
        IT_S_A_GOOD_THING_TOO                                                                       = 14966,  -- It's a good thing, too.
        CAUSE_YA_VE_GOT_ENOUGH_DEBT_RACKED_UP                                                       = 14967,  -- 'Cause ya've got enough debt racked up t' fill Mount Zhayolm a hundrrred times over!
        ABQUHBAH_21                                                                                 = 14968,  -- Abquhbah!
        Y_YES_PRESIDENT_NAJA_2                                                                      = 14969,  -- Y-yes, President Naja!
        READ_OFF_THE_LIST_OF_EXPENSES_INCURRRED_BY                                                  = 14970,  -- Read off the list of expenses incurrred by [/Private Second Class/Private First Class/Superior Private/Lance Corporal/Corporal/Sergeant/Sergeant Major/Chief Sergeant/Second Lieutenant/First Lieutenant/Captain] %, here.
        ER_Y_YES_PRESIDENT_NAJA_THE_YET_UNPAID                                                      = 14971,  -- Er, y-yes, President Naja. The yet-unpaid fee for a perilous rescue at Nyzul Isle, plus cleaning costs, travel fees and peripheral expenses. With all accrued interest, that comes to...
        NO_I_JUST_DON_T_HAVE_THE_HEART                                                              = 14972,  -- No... I just don't have the heart to go on! M-Madam President, forgive meeeeeeeee!
        DON_T_GIVE_ME_THOSE_PLEADIN_LITTLE_KITTEN                                                   = 14973,  -- Don't give me those pleadin' little kitten eyes, %. I'd hafta be blind not t' see that ya've earrrned your keep this time.
        SO_I_LL_OVERLOOK_YOUR_DEBT_FOR_TODAY                                                        = 14974,  -- So I'll overlook your debt for today and give you this hard-earrrned Imperial gold piece. No need ta thank me. Just don't spend it all in one place, ya hear?
        INCREDIBLE_MADAM_PRESIDENT_TRULY_YOUR_GENEROSITY_KNOWS_NO                                   = 14975,  -- Incredible, Madam President! Truly, your generosity knows no bounds!
        IT_S_NOT_EVERY_DAY_THAT_A_MERCENARY                                                         = 14976,  -- It's not every day that a mercenary earns a bonus from President Naja herself. Stand tall, %! You truly are the cream of the crop!
        FALZUM_LET_S_HEAR_YER_EXPLANATION_AND_IT                                                    = 14977,  -- Falzum! Let's hear yer explanation...and it'd better be a good one!
        P_PRESIDENT_NAJA_I_W_WAS_I_I                                                                = 14978,  -- P-President Naja...I w-was...I-I am... So soooooooooooorrryyyyyy!
        CUT_THE_SNIVELING_ALL_YER_APOLOGIES_WON_T                                                   = 14979,  -- Cut the sniveling! All yer apologies won't amount to a single brrronze piece!
        SNIFF_Y_YES_MA_AM                                                                           = 14980,  -- <Sniff>...Y-Yes, ma'am.
        I_SNIFFLE_S_SEARCHED_FWOM_THE_WAJAOM_WOODWADS                                               = 14981,  -- I...<sniffle>...s-searched fwom the Wajaom Woodwads t-to the Bhafwau Thickets, b-but...
        H_HE_S_S_SHE_S_NOWHERE_TO                                                                   = 14982,  -- %...h-he's/s-she's] nowhere to b-bwe...<sniffle>...fwound!
        HANG_IN_THERE_FALZUM_IT_S_ONLY_A                                                            = 14983,  -- (Hang in there, Falzum! It's only a matter of time before--)
        ID_14984                                                                                    = 14984,  -- %!
