        OUR_RESEARCHERS_DISCOVERED_THAT_THIS_ACTED_AS_A                                             = 15083,  -- Our researchers discovered that this % acted as...a key. A key that could grant anyone possessing one effortless access to the Empire's most strictly guarded facility.
